import Vue from 'vue';
//配置路由
import VueRouter from 'vue-router'
Vue.use(VueRouter);
//1.创建组件
import Index from '@/views/index'
import Home from '@/views/home'
import Login from '@/views/login'
import NotFound from '@/views/404'
import UpdatePassword from '@/views/update-password'
import pay from '@/views/pay'
import register from '@/views/register'
import center from '@/views/center'
    import news from '@/views/modules/news/list'
    import huifuxinxi from '@/views/modules/huifuxinxi/list'
    import zaixiangoutong from '@/views/modules/zaixiangoutong/list'
    import discussxizhuangxinxi from '@/views/modules/discussxizhuangxinxi/list'
    import shangjia from '@/views/modules/shangjia/list'
    import friendlink from '@/views/modules/friendlink/list'
    import systemintro from '@/views/modules/systemintro/list'
    import yonghu from '@/views/modules/yonghu/list'
    import chat from '@/views/modules/chat/list'
    import xizhuangxinxi from '@/views/modules/xizhuangxinxi/list'
    import orders from '@/views/modules/orders/list'
    import xizhuangdingzhi from '@/views/modules/xizhuangdingzhi/list'
    import xizhuangfenlei from '@/views/modules/xizhuangfenlei/list'
    import config from '@/views/modules/config/list'
    import newstype from '@/views/modules/newstype/list'


//2.配置路由   注意：名字
export const routes = [{
    path: '/',
    name: '系统首页',
    component: Index,
    children: [{
      // 这里不设置值，是把main作为默认页面
      path: '/',
      name: '系统首页',
      component: Home,
      meta: {icon:'', title:'center', affix: true}
    }, {
      path: '/updatePassword',
      name: '修改密码',
      component: UpdatePassword,
      meta: {icon:'', title:'updatePassword'}
    }, {
      path: '/pay',
      name: '支付',
      component: pay,
      meta: {icon:'', title:'pay'}
    }, {
      path: '/center',
      name: '个人信息',
      component: center,
      meta: {icon:'', title:'center'}
    }
      ,{
	path: '/news',
        name: '公告信息',
        component: news
      }
      ,{
	path: '/huifuxinxi',
        name: '回复信息',
        component: huifuxinxi
      }
      ,{
	path: '/zaixiangoutong',
        name: '在线沟通',
        component: zaixiangoutong
      }
      ,{
	path: '/discussxizhuangxinxi',
        name: '预制菜信息评论',
        component: discussxizhuangxinxi
      }
      ,{
	path: '/shangjia',
        name: '商家',
        component: shangjia
      }
      ,{
	path: '/friendlink',
        name: '友情链接',
        component: friendlink
      }
      ,{
	path: '/systemintro',
        name: '系统简介',
        component: systemintro
      }
      ,{
	path: '/yonghu',
        name: '用户',
        component: yonghu
      }
      ,{
	path: '/chat',
        name: '客服反馈',
        component: chat
      }
      ,{
	path: '/xizhuangxinxi',
        name: '预制菜信息',
        component: xizhuangxinxi
      }
      ,{
        path: '/orders/:status',
        name: '订单管理',
        component: orders
      }
      ,{
	path: '/xizhuangdingzhi',
        name: '预制菜定制',
        component: xizhuangdingzhi
      }
      ,{
	path: '/xizhuangfenlei',
        name: '预制菜分类',
        component: xizhuangfenlei
      }
      ,{
	path: '/config',
        name: '轮播图管理',
        component: config
      }
      ,{
	path: '/newstype',
        name: '公告信息分类',
        component: newstype
      }
    ]
  },
  {
    path: '/login',
    name: 'login',
    component: Login,
    meta: {icon:'', title:'login'}
  },
  {
    path: '/register',
    name: 'register',
    component: register,
    meta: {icon:'', title:'register'}
  },
  {
    path: '*',
    component: NotFound
  }
]
//3.实例化VueRouter  注意：名字
const router = new VueRouter({
  mode: 'hash',
  /*hash模式改为history*/
  routes // （缩写）相当于 routes: routes
})
const originalPush = VueRouter.prototype.push
//修改原型对象中的push方法
VueRouter.prototype.push = function push(location) {
   return originalPush.call(this, location).catch(err => err)
}
export default router;
