<script>
// 数字，邮件，手机，url，身份证校验
import { isNumber,isIntNumer,isEmail,isPhone, isMobile,isURL,checkIdCard } from "@/utils/validate";
export default {
	data() {
		let self = this
		var validateIdCard = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!checkIdCard(value)) {
				callback(new Error("请输入正确的身份证号码"));
			} else {
				callback();
			}
		};
		var validateUrl = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isURL(value)) {
				callback(new Error("请输入正确的URL地址"));
			} else {
				callback();
			}
		};
		var validateMobile = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isMobile(value)) {
				callback(new Error("请输入正确的手机号码"));
			} else {
				callback();
			}
		};
		var validatePhone = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isPhone(value)) {
				callback(new Error("请输入正确的电话号码"));
			} else {
				callback();
			}
		};
		var validateEmail = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isEmail(value)) {
				callback(new Error("请输入正确的邮箱地址"));
			} else {
				callback();
			}
		};
		var validateNumber = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isNumber(value)) {
				callback(new Error("请输入数字"));
			} else {
				callback();
			}
		};
		var validateIntNumber = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isIntNumer(value)) {
				callback(new Error("请输入整数"));
			} else {
				callback();
			}
		};
		return {
			id: '',
			type: '',
			
			
			ro:{
				dianpumingcheng : false,
				xizhuangmingcheng : false,
				xizhuangfenlei : false,
				pinpai : false,
				fengmian : false,
				yanse : false,
				caizhi : false,
				chima : false,
				dingzhijiage : false,
				jianshu : false,
				xizhuangxiangqing : false,
				onelimittimes : false,
				alllimittimes : false,
				clicktime : false,
				clicknum : false,
				discussnum : false,
				price : false,
				storeupnum : false,
			},
			
			
			ruleForm: {
				dianpumingcheng: '',
				xizhuangmingcheng: '',
				xizhuangfenlei: '',
				pinpai: '',
				fengmian: '',
				yanse: '',
				caizhi: '',
				chima: '',
				dingzhijiage: '',
				jianshu: '',
				xizhuangxiangqing: '',
				onelimittimes: '-1',
				alllimittimes: '-1',
				clicktime: '',
				price: '',
			},
		
			xizhuangfenleiOptions: [],
			pinpaiOptions: [],
			chimaOptions: [],

			
			rules: {
				dianpumingcheng: [
				],
				xizhuangmingcheng: [
					{ required: true, message: '预制菜名称不能为空', trigger: 'blur' },
				],
				xizhuangfenlei: [
					{ required: true, message: '预制菜分类不能为空', trigger: 'blur' },
				],
				pinpai: [
				],
				fengmian: [
				],
				yanse: [
				],
				caizhi: [
				],
				chima: [
				],
				dingzhijiage: [
					{ required: true, message: '定制价格不能为空', trigger: 'blur' },
					{ validator: validateNumber, trigger: 'blur' },
				],
				jianshu: [
				],
				xizhuangxiangqing: [
				],
				onelimittimes: [
					{ validator: validateIntNumber, trigger: 'blur' },
				],
				alllimittimes: [
					{ validator: validateIntNumber, trigger: 'blur' },
				],
				clicktime: [
				],
				clicknum: [
					{ validator: validateIntNumber, trigger: 'blur' },
				],
				discussnum: [
					{ validator: validateIntNumber, trigger: 'blur' },
				],
				price: [
					{ required: true, message: '价格不能为空', trigger: 'blur' },
					{ validator: validateNumber, trigger: 'blur' },
				],
				storeupnum: [
					{ validator: validateIntNumber, trigger: 'blur' },
				],
			}
		};
	},
	props: ["parent"],
	computed: {



	},
    components: {
    },
	created() {
	},
	methods: {
		
		// 下载
		download(file){
			window.open(`${file}`)
		},
		// 初始化
		init(id,type) {
			if (id) {
				this.id = id;
				this.type = type;
			}
			if(this.type=='info'||this.type=='else'){
				this.info(id);
			}else if(this.type=='logistics'){
				this.logistics=false;
				this.info(id);
			}else if(this.type=='cross'){
				var obj = this.$storage.getObj('crossObj');
				for (var o in obj){
						if(o=='dianpumingcheng'){
							this.ruleForm.dianpumingcheng = obj[o];
							this.ro.dianpumingcheng = true;
							continue;
						}
						if(o=='xizhuangmingcheng'){
							this.ruleForm.xizhuangmingcheng = obj[o];
							this.ro.xizhuangmingcheng = true;
							continue;
						}
						if(o=='xizhuangfenlei'){
							this.ruleForm.xizhuangfenlei = obj[o];
							this.ro.xizhuangfenlei = true;
							continue;
						}
						if(o=='pinpai'){
							this.ruleForm.pinpai = obj[o];
							this.ro.pinpai = true;
							continue;
						}
						if(o=='fengmian'){
							this.ruleForm.fengmian = obj[o];
							this.ro.fengmian = true;
							continue;
						}
						if(o=='yanse'){
							this.ruleForm.yanse = obj[o];
							this.ro.yanse = true;
							continue;
						}
						if(o=='caizhi'){
							this.ruleForm.caizhi = obj[o];
							this.ro.caizhi = true;
							continue;
						}
						if(o=='chima'){
							this.ruleForm.chima = obj[o];
							this.ro.chima = true;
							continue;
						}
						if(o=='dingzhijiage'){
							this.ruleForm.dingzhijiage = obj[o];
							this.ro.dingzhijiage = true;
							continue;
						}
						if(o=='jianshu'){
							this.ruleForm.jianshu = obj[o];
							this.ro.jianshu = true;
							continue;
						}
						if(o=='xizhuangxiangqing'){
							this.ruleForm.xizhuangxiangqing = obj[o];
							this.ro.xizhuangxiangqing = true;
							continue;
						}
						if(o=='onelimittimes'){
							this.ruleForm.onelimittimes = obj[o];
							this.ro.onelimittimes = true;
							continue;
						}
						if(o=='alllimittimes'){
							this.ruleForm.alllimittimes = obj[o];
							this.ro.alllimittimes = true;
							continue;
						}
						if(o=='clicktime'){
							this.ruleForm.clicktime = obj[o];
							this.ro.clicktime = true;
							continue;
						}
						if(o=='clicknum'){
							this.ruleForm.clicknum = obj[o];
							this.ro.clicknum = true;
							continue;
						}
						if(o=='discussnum'){
							this.ruleForm.discussnum = obj[o];
							this.ro.discussnum = true;
							continue;
						}
						if(o=='price'){
							this.ruleForm.price = obj[o];
							this.ro.price = true;
							continue;
						}
						if(o=='storeupnum'){
							this.ruleForm.storeupnum = obj[o];
							this.ro.storeupnum = true;
							continue;
						}
				}
				












				this.ruleForm.onelimittimes = Number('-1'); 
				this.ruleForm.alllimittimes = Number('-1'); 




			}
			
			// 获取用户信息
			this.$http({
				url: `${this.$storage.get('sessionTable')}/session`,
				method: "get"
			}).then(({ data }) => {
				if (data && data.code === 0) {
					
					var json = data.data;
					if(((json.dianpumingcheng!=''&&json.dianpumingcheng) || json.dianpumingcheng==0) && this.$storage.get("role")!="管理员"){
						this.ruleForm.dianpumingcheng = json.dianpumingcheng
						this.ro.dianpumingcheng = true;
					}
					if(this.$storage.get("role")!="管理员") {
						this.ro.dianpumingcheng = true;
					}
				} else {
					this.$message.error(data.msg);
				}
			});
			
            this.$http({
				url: `option/xizhuangfenlei/xizhuangfenlei`,
				method: "get"
            }).then(({ data }) => {
				if (data && data.code === 0) {
					this.xizhuangfenleiOptions = data.data;
				} else {
					this.$message.error(data.msg);
				}
            });
            this.pinpaiOptions = "GUCCI,LV,YSL,COACH".split(',')
            this.chimaOptions = "S,M,L,XL,XXL,XXXL".split(',')
			
		},
    // 多级联动参数

    info(id) {
      this.$http({
        url: `xizhuangxinxi/info/${id}`,
        method: "get"
      }).then(({ data }) => {
        if (data && data.code === 0) {
        this.ruleForm = data.data;
        //解决前台上传图片后台不显示的问题
        let reg=new RegExp('../../../upload','g')//g代表全部
        this.ruleForm.xizhuangxiangqing = this.ruleForm.xizhuangxiangqing.replace(reg,'../../../springboot01u2zqkf/upload');
        } else {
          this.$message.error(data.msg);
        }
      });
    },


    // 提交
    onSubmit() {
	  if(this.ruleForm.price<0){
		this.$message.error("价格不能输入负数");
		return
	  }
	  if(this.ruleForm.alllimittimes<0){
		this.$message.error("库存不能输入负数");
		return
	  }
	  if(this.ruleForm.onelimittimes<0){
		this.$message.error("单次购买不能输入负数");
		return
	  }

	  if(this.ruleForm.price<0){
		this.$message.error("价格不能输入负数");
		return
	  }
	  if(this.ruleForm.alllimittimes<0){
		this.$message.error("库存不能输入负数");
		return
	  }
	  if(this.ruleForm.onelimittimes<0){
		this.$message.error("单次购买不能输入负数");
		return
	  }

	  if(this.ruleForm.price<0){
		this.$message.error("价格不能输入负数");
		return
	  }
	  if(this.ruleForm.alllimittimes<0){
		this.$message.error("库存不能输入负数");
		return
	  }
	  if(this.ruleForm.onelimittimes<0){
		this.$message.error("单次购买不能输入负数");
		return
	  }

	  if(this.ruleForm.price<0){
		this.$message.error("价格不能输入负数");
		return
	  }
	  if(this.ruleForm.alllimittimes<0){
		this.$message.error("库存不能输入负数");
		return
	  }
	  if(this.ruleForm.onelimittimes<0){
		this.$message.error("单次购买不能输入负数");
		return
	  }

	  if(this.ruleForm.price<0){
		this.$message.error("价格不能输入负数");
		return
	  }
	  if(this.ruleForm.alllimittimes<0){
		this.$message.error("库存不能输入负数");
		return
	  }
	  if(this.ruleForm.onelimittimes<0){
		this.$message.error("单次购买不能输入负数");
		return
